export const RECOVERY_L3 = new Set(['power_nap','long_nap','rest_lying','mental_rest','guided_meditation','breathing_exercise','silent_meditation','contemplation','chanting','daily_prayer','morning_prayer','afternoon_snack','dessert']);

export function isRecovery(l4) { return l4 ? (RECOVERY_L3.has(l4.l3) || RECOVERY_L3.has(l4.tag)) : false; }

export function getL4(tag) { return L4_DB[tag] || null; }

export function getL3Siblings(tag) { const e = L4_DB[tag]; if (!e) return []; return TREE[e.l1]?.[e.l2]?.[e.l3] || []; }